"use client"

import { useState, useEffect } from "react"
import { Button } from "@/components/ui/button"
import { WorkshopLoader } from "@/components/workshop-loader"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card"
import { Alert, AlertDescription } from "@/components/ui/alert"
import { Eye, EyeOff, Mail, Lock, User } from "lucide-react"
import { useAuth } from "@/lib/auth-context"

interface SignInScreenProps {
  onSwitchToSignup: () => void
}

export function SignInScreen({ onSwitchToSignup }: SignInScreenProps) {
  const { login } = useAuth()
  const [showPassword, setShowPassword] = useState(false)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [error, setError] = useState("")
  const [isLoading, setIsLoading] = useState(true)

  // Storage Keys
  const STORAGE_KEY = 'workshop_user_profile' // The DB - NEVER DELETE THIS

  const [formData, setFormData] = useState({
    email: "",
    password: ""
  })

  // Show loader on initial mount
  useEffect(() => {
    const timer = setTimeout(() => setIsLoading(false), 600)
    return () => clearTimeout(timer)
  }, [])

  // Handle form submission
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setError("")
    setIsSubmitting(true)

    try {
      // 1. Read "Database"
      const json = localStorage.getItem(STORAGE_KEY)

      // 2. Validation
      if (!json) {
        setError("No account found. Please sign up.")
        return
      }

      const user = JSON.parse(json)

      if (user.email !== formData.email.trim() || user.password !== formData.password) {
        setError("Invalid email or password.")
        return
      }

      // 3. Success
      console.log("Sign In | User data from localStorage:", user)
      login(user)
      console.log("Sign In | User logged in successfully:", user)

    } catch (error) {
      console.error("Sign In | Error during login:", error)
      setError("An error occurred. Please try again.")
    } finally {
      setIsSubmitting(false)
    }
  }

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center p-4">
        <WorkshopLoader size="large" loadingText="Loading Sign In..." />
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-background via-background to-primary/5 dark:from-background dark:via-background dark:to-primary/10 flex items-center justify-center p-4">
      <Card className="w-full max-w-xl bg-card/95 backdrop-blur-xl shadow-2xl border-border/50 rounded-2xl p-10">
        <CardHeader className="space-y-4 text-center">
          {/* Logo */}
          <div className="flex justify-center">
            <img
              src="/logo.jpeg"
              alt="Workshop Profit PilotLogo"
              className="h-20 w-auto"
            />
          </div>

          <div className="space-y-2">
            <CardTitle className="text-2xl font-bold text-slate-900 dark:text-white">
              Welcome Back
            </CardTitle>
            <CardDescription className="text-slate-500 dark:text-slate-400 text-sm">
              Sign in to your workspace
            </CardDescription>
          </div>
        </CardHeader>

        <form onSubmit={handleSubmit}>
          <CardContent className="space-y-4">
            {/* Email */}
            <div className="space-y-2">
              <Label htmlFor="email" className="text-foreground">Email Address</Label>
              <div className="relative">
                <Mail className="absolute left-3 top-3 h-4 w-4 text-slate-400" />
                <Input
                  id="email"
                  type="email"
                  placeholder="john@example.com"
                  value={formData.email}
                  onChange={(e) => {
                    setFormData(prev => ({ ...prev, email: e.target.value }))
                    if (error) setError("")
                  }}
                  className={`h-12 pl-10 rounded-lg border-slate-200 focus:ring-2 focus:ring-teal-500 ${error ? 'border-destructive' : ''}`}
                  required
                />
              </div>
            </div>

            {/* Password */}
            <div className="space-y-2">
              <Label htmlFor="password" className="text-slate-700 dark:text-slate-300">Password</Label>
              <div className="relative">
                <Lock className="absolute left-3 top-3 h-4 w-4 text-slate-400" />
                <Input
                  id="password"
                  type={showPassword ? "text" : "password"}
                  placeholder="Enter your password"
                  value={formData.password}
                  onChange={(e) => {
                    setFormData(prev => ({ ...prev, password: e.target.value }))
                    if (error) setError("")
                  }}
                  className={`h-12 pl-10 pr-10 rounded-lg border-border bg-input focus:ring-2 focus:ring-primary/20 focus:border-primary/50 ${error ? 'border-destructive' : ''}`}
                  required
                />
                <Button
                  type="button"
                  variant="ghost"
                  size="sm"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-1 top-1 h-9 w-9 p-0"
                >
                  {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                </Button>
              </div>
            </div>

            {/* Error Alert */}
            {error && (
              <Alert variant="destructive">
                <AlertDescription>{error}</AlertDescription>
              </Alert>
            )}

            {/* Forgot Password Link */}
            <div className="text-right">
              <Button type="button" variant="ghost" className="p-0 h-auto text-sm text-primary hover:text-primary/80">
                Forgot your password?
              </Button>
            </div>
          </CardContent>

          <CardFooter className="flex flex-col space-y-4 pt-6">
            <Button
              type="submit"
              className="w-full h-12 bg-primary hover:bg-primary/90 text-primary-foreground font-bold rounded-lg transition-all duration-200 shadow-lg shadow-primary/20 hover:shadow-primary/30"
              disabled={isSubmitting}
            >
              {isSubmitting ? "Signing In..." : "Sign In"}
            </Button>

            <div className="text-center text-sm text-muted-foreground">
              Don't have an account?{" "}
              <Button
                type="button"
                variant="ghost"
                className="p-0 h-auto text-primary hover:text-primary/80 underline"
                onClick={onSwitchToSignup}
              >
                Create one
              </Button>
            </div>
          </CardFooter>
        </form>
      </Card>
    </div>
  )
}
